        <div className="flex bg-white/50 p-1 rounded-2xl border-2 border-black">
          {(['MY_VIBES', 'TOAST_CREW', 'MY_NETWORK'] as const).map(tab => (
            <button
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`flex-1 py-2 text-xs font-black rounded-xl transition-all ${
                activeTab === tab ? 'bg-black text-white' : 'text-gray-600'
              }`}
            >
              {tab.replace('_', ' ')}
            </button>
          ))}
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6 pt-2">
        {activeTab === 'MY_VIBES' && (
          <div className="space-y-4">
             <div className="bg-[#d1f9e5] p-6 cute-card rounded-3xl">
                <div className="flex justify-between mb-4">
                   <div className="bg-white px-3 py-1 rounded-full border border-black text-xs font-bold">
                      Today: {history[0]?.hoursWorked.toFixed(1) || 0}h
