             </div>

             <TimelineGraph data={history} />

             <h2 className="text-xs font-black text-gray-400 uppercase ml-2">History Logs</h2>
             {history.map((log, i) => (
                <div key={i} className="bg-white p-4 cute-card rounded-2xl flex justify-between items-center">
