                      </div>
                   </div>
                   <div className="text-right flex-shrink-0">
                      <p className="font-black text-sm text-green-700">${peer.hourlyRate.toFixed(0)} <span className="text-[10px]">/hr</span></p>
                   </div>
                </div>
                <div className="flex justify-end gap-2 mt-2">
