                    onClick={() => toggleHug(peer.id)}
                    className={`px-4 py-1.5 rounded-full border-2 border-black text-[10px] font-black transition-all ${
                      hugs[peer.id] ? 'bg-pink-400 text-white shadow-none translate-x-0.5 translate-y-0.5' : 'bg-white shadow-[2px_2px_0px_0px_#000]'
