                <div key={i} className="bg-white p-4 cute-card rounded-2xl flex justify-between items-center group">
                   <div className="flex-1">
                      <p className="text-xs font-bold text-gray-400">{log.date}</p>
                      <p className="font-black text-lg">${log.hourlyRate.toFixed(0)} / hr</p>
                      {log.startTimeStr && (
                        <p className="text-[10px] font-bold text-gray-400 mt-1">
                          Grind: {log.startTimeStr} → {log.endTimeStr}
                        </p>
                      )}
                   </div>
                   <div className="text-3xl">
                      {log.vibe === 'Sushi' ? '🍣' : log.vibe === 'Salad' ? '🥗' : '🥖'}
                   </div>
                </div>
             ))}
          </div>
        )}

        {activeTab === 'TOAST_CREW' && (
          <div className="space-y-4 pb-8 px-2">
            <h2 className="text-center font-black text-purple-800 text-xl py-2 uppercase tracking-tighter">比惨大会 (Toast Crew)</h2>
            {MOCK_PEERS.map(peer => (
              <div key={peer.id} className="bg-white p-4 cute-card rounded-2xl ml-4 mr-2">
                <div className="flex justify-between items-start mb-2">
                   <div className="flex gap-10 items-center">
                      <div className="w-16 h-16 relative flex-shrink-0">
                         <CuteCharacter 
                           mood={peer.vibe === 'Sushi' ? 'happy' : peer.vibe === 'Salad' ? 'chill' : 'sad'} 
                           size={64} 
                           accessory={peer.vibe === 'Sushi' ? 'sushi' : peer.vibe === 'Bread' ? 'toast' : 'none'} 
                         />
                      </div>
                      <div className="pt-1">
                         <p className="font-black text-base">{peer.name}</p>
                         <p className="text-[10px] font-bold text-gray-500">{peer.company} · {peer.jobTitle}</p>
                         <p className="text-[10px] font-bold text-gray-400 tracking-tight">Hours: {peer.hoursWorked}h</p>
                      </div>
                   </div>
                   <div className="text-right flex-shrink-0">
                      <p className="font-black text-sm text-green-700">${peer.hourlyRate.toFixed(0)} <span className="text-[10px]">/hr</span></p>
                   </div>
                </div>
                <div className="flex justify-end gap-2 mt-2">
                   <button 
                    onClick={() => toggleHug(peer.id)}
                    className={`px-4 py-1.5 rounded-full border-2 border-black text-[10px] font-black transition-all ${
                      hugs[peer.id] ? 'bg-pink-400 text-white shadow-none translate-x-0.5 translate-y-0.5' : 'bg-white shadow-[2px_2px_0px_0px_#000]'
                    }`}
                   >
                     {hugs[peer.id] ? 'Sent Hug! ❤️' : 'Send Hug 🤗'}
                   </button>
                </div>
              </div>
            ))}
          </div>
        )}

        {activeTab === 'MY_NETWORK' && (
          <div className="space-y-4 pb-8">
             <div className="bg-[#fff9e6] p-4 cute-card rounded-2xl text-center mb-6">
                <p className="text-sm font-black uppercase tracking-widest">Market Benchmarks</p>
             </div>
             {MOCK_NETWORK.map((item, i) => (
               <div key={i} className="bg-white p-5 cute-card rounded-3xl flex justify-between items-center">
                  <div className="flex gap-4 items-center">
                    <div className="w-12 h-12 bg-blue-50 border-2 border-black rounded-2xl flex items-center justify-center font-black text-blue-600 shadow-[2px_2px_0px_0px_#000]">
                       {item.company[0]}
                    </div>
                    <div>
                       <h3 className="font-black text-lg">{item.company}</h3>
                       <p className="text-xs text-gray-500 font-bold">{item.role}</p>
                    </div>
                  </div>
                  <div className="text-right">
                     <p className="font-black text-lg">${item.baseRate.toFixed(0)} / hr</p>
                     <p className="text-[10px] font-bold text-green-500">{item.vibe} Vibe</p>
                  </div>
               </div>
             ))}
          </div>
        )}
      </div>

      <div className="p-4 flex justify-center bg-white border-t-2 border-black">
         <div className="flex flex-col items-center">
            <div className="w-8 h-8 mb-1">
               <CuteCharacter mood="happy" size={32} />
            </div>
            <p className="text-[8px] font-bold text-gray-400 uppercase tracking-widest">#OffWorkYet</p>
         </div>
      </div>
    </div>
  );
};
